// The previous attempt added two `assert(forall|...| ... ==> er.view() == er.view())`
// extensionality hints. Those failed: `EventResults::view` and `NetClient::view`
// are `closed spec fn`s, so Verus cannot prove a generic field-to-view
// extensionality lemma — the bodies are invisible to the prover. We drop
// those (they were the 2 errors in attempt_01) and instead lift each
// conjunct of `HostState::next_ensures` into the proof context as an
// UNCONDITIONAL top-level implication for r1 and r2 separately. Each
// implication is a tautology that Verus discharges by inlining the
// open-spec body of `next_ensures`, but it surfaces matching predicate
// shapes for the two runs so z3 can pattern-match them symmetrically.
// We then unfold `event_seq` and the synthetic `det_..._equal` predicate
// so the goal is named in terms of its four component equalities.

let (ok1, res1) = r1;
let (ok2, res2) = r2;
let er1 = res1@;
let er2 = res2@;

// Conjunct 1: ok matches new_netc.ok().
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> ok1 == post1_netc.ok());
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> ok2 == post2_netc.ok());

// Conjunct 2: ok ==> invariants on (new_self, new_netc).
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (ok1 ==> post1_self_.invariants(&post1_netc.my_end_point())));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (ok2 ==> post2_self_.invariants(&post2_netc.my_end_point())));

// Conjunct 3: ok ==> the abstract `next` relation holds with the same
// pre_self_@ on both sides — the structural pairing z3 must line up.
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (ok1 ==> HostState::next(pre_self_.view(), post1_self_.view(), er1.ios)));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (ok2 ==> HostState::next(pre_self_.view(), post2_self_.view(), er2.ios)));

// Conjunct 4: ok ==> event_seq() == ios — links the synthetic ios used
// by `next` back to the recvs/clocks/sends triple inside the closed
// `EventResults::view`.
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (ok1 ==> er1.event_seq() == er1.ios));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (ok2 ==> er2.event_seq() == er2.ios));

// Conjunct 5: history-append equation — the only constraint that pins
// down `post_netc.history()` (the closed NetClientView.history field).
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> ((ok1 || er1.sends.len() > 0)
        ==> post1_netc.history() == pre_netc.history() + er1.event_seq()));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> ((ok2 || er2.sends.len() > 0)
        ==> post2_netc.history() == pre_netc.history() + er2.event_seq()));

// Conjunct 6: well_typed_events — the forall quantifiers inside are
// usually the source of the trigger gap, so surface them explicitly
// for both runs.
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> er1.well_typed_events());
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> er2.well_typed_events());

// Unfold `event_seq` so its three-way concatenation is visible at the
// top level — gives z3 a syntactic bridge from the equation in conjunct
// 5 to the recvs/clocks/sends fields needed for EventResults::view().
assert(er1.event_seq() == er1.recvs + er1.clocks + er1.sends);
assert(er2.event_seq() == er2.recvs + er2.clocks + er2.sends);

// Unfold the synthetic determinism predicate so each conjunct of the
// conclusion is named separately. `det_receive_packet_next_equal` is
// an `open spec fn` (it is the generated equal_fn), so the equation
// below is discharged by inlining its body. This is the single point
// at which z3 can attempt to discharge the whole equality from the
// six conjunct facts above.
assert(det_receive_packet_next_equal(r1, r2, post1_self_@, post2_self_@, post1_netc, post2_netc)
    == ((r1.0 == r2.0)
        && ((r1.1)@.view() == (r2.1)@.view())
        && (post1_self_@ == post2_self_@)
        && (post1_netc.view() == post2_netc.view())));
